// GinServerOptions provides options for the Gin server.
type GinServerOptions struct {
	BaseURL      string
	Middlewares  []MiddlewareFunc
	ErrorHandler func(*gin.Context, error, int)
}

// RegisterHandlers creates http.Handler with routing matching OpenAPI spec.
func RegisterHandlers(router gin.IRouter, si ServerInterface) {
	RegisterHandlersWithOptions(router, si, GinServerOptions{})
}

// RegisterHandlersWithOptions creates http.Handler with additional options
func RegisterHandlersWithOptions(router gin.IRouter, si ServerInterface, options GinServerOptions) {
	errorHandler := options.ErrorHandler
	if errorHandler == nil {
		errorHandler = func(c *gin.Context, err error, statusCode int) {
			c.JSON(statusCode, gin.H{"msg": err.Error()})
		}
	}

	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandler:       errorHandler,
	}

	router.POST(options.BaseURL+"/v1/auth/clerk/sign-in-token", wrapper.CreateClerkSignInToken)
	router.GET(options.BaseURL+"/v1/git-access-tokens", wrapper.ListGitAccessTokens)
	router.POST(options.BaseURL+"/v1/git-access-tokens", wrapper.CreateGitAccessToken)
	router.DELETE(options.BaseURL+"/v1/git-access-tokens/:id", wrapper.RevokeGitAccessToken)
	router.GET(options.BaseURL+"/v1/healthz", wrapper.Healthz)
	router.POST(options.BaseURL+"/v1/repositories", wrapper.CreateRepository)
	router.GET(options.BaseURL+"/v1/repositories/:owner/:repository", wrapper.GetRepositoryByOwnerAndName)
	router.PATCH(options.BaseURL+"/v1/repositories/:owner/:repository", wrapper.UpdateRepository)
	router.GET(options.BaseURL+"/v1/repositories/:owner/:repository/file", wrapper.GetRepositoryFile)
	router.GET(options.BaseURL+"/v1/repositories/:owner/:repository/git-path/resolve", wrapper.ResolveRepositoryGitPath)
	router.GET(options.BaseURL+"/v1/repositories/:owner/:repository/issues", wrapper.ListRepositoryIssues)
	router.POST(options.BaseURL+"/v1/repositories/:owner/:repository/issues", wrapper.CreateRepositoryIssue)
	router.GET(options.BaseURL+"/v1/repositories/:owner/:repository/issues/:number", wrapper.GetRepositoryIssue)
	router.GET(options.BaseURL+"/v1/repositories/:owner/:repository/latest-commit", wrapper.GetRepositoryLatestCommit)
	router.GET(options.BaseURL+"/v1/repositories/:owner/:repository/readme", wrapper.GetRepositoryReadme)
	router.GET(options.BaseURL+"/v1/repositories/:owner/:repository/refs", wrapper.ListRepositoryRefs)
	router.GET(options.BaseURL+"/v1/repositories/:owner/:repository/tree", wrapper.GetRepositoryTree)
	router.GET(options.BaseURL+"/v1/user", wrapper.GetAuthenticatedUser)
	router.PATCH(options.BaseURL+"/v1/user", wrapper.UpdateAuthenticatedUser)
	router.GET(options.BaseURL+"/v1/users/clerk/:clerkUserId", wrapper.GetUserByClerkUserId)
	router.GET(options.BaseURL+"/v1/users/name/:name", wrapper.GetUserByName)
	router.GET(options.BaseURL+"/v1/version", wrapper.Version)
}

